package com.grit.liferecorder.ui.calendar
import androidx.compose.foundation.background; import androidx.compose.foundation.layout.*; import androidx.compose.foundation.lazy.LazyColumn; import androidx.compose.foundation.shape.CircleShape; import androidx.compose.material3.*; import androidx.compose.runtime.*; import androidx.compose.ui.*; import androidx.compose.ui.graphics.Color; import androidx.compose.ui.text.font.FontWeight; import androidx.compose.ui.unit.dp; import androidx.lifecycle.compose.collectAsStateWithLifecycle; import com.grit.liferecorder.core.date.*; import com.grit.liferecorder.data.repository.DayAggregate; import com.grit.liferecorder.ui.theme.*; import java.time.*
@Composable fun CalendarScreen(viewModel:CalendarViewModel,padding:PaddingValues){ val state by viewModel.state.collectAsStateWithLifecycle(); LazyColumn(Modifier.padding(padding).fillMaxSize().background(MaterialTheme.colorScheme.background),contentPadding=PaddingValues(16.dp),verticalArrangement=Arrangement.spacedBy(16.dp)){ item{ MonthCalendar(state,viewModel::previousMonth,viewModel::nextMonth,viewModel::select) }; item{ TodaySection(state.selectedDate){ viewModel.select(DateUtils.today()) } }; item{ DayDetailPanel(state.selectedDate,state.selected,viewModel::saveJournal) } } }
@Composable fun MonthCalendar(state:CalendarUiState,onPrev:()->Unit,onNext:()->Unit,onSelect:(String)->Unit){ Card{ Column(Modifier.padding(16.dp)){ Row(Modifier.fillMaxWidth(),horizontalArrangement=Arrangement.SpaceBetween,verticalAlignment=Alignment.CenterVertically){ TextButton(onClick=onPrev){Text("‹")}; Text(DateUtils.monthTitle(state.month),style=MaterialTheme.typography.titleLarge,fontWeight=FontWeight.SemiBold); TextButton(onClick=onNext){Text("›")} }; Row(Modifier.fillMaxWidth(),horizontalArrangement=Arrangement.SpaceAround){ listOf("S","M","T","W","T","F","S").forEach{ Text(it,color=MaterialTheme.colorScheme.onSurfaceVariant) } }; val first=state.month.atDay(1); val blanks=first.dayOfWeek.value%7; val cells=(List(blanks){null}+(1..state.month.lengthOfMonth()).map{state.month.atDay(it)}).chunked(7); cells.forEach{week-> Row(Modifier.fillMaxWidth(),horizontalArrangement=Arrangement.SpaceAround){ week.forEach{date-> CalendarDayCell(date,state.selectedDate,state.days.find{it.date==date?.format(DateUtils.iso)},onSelect,Modifier.weight(1f)) }; repeat(7-week.size){ Spacer(Modifier.weight(1f)) } } } } } }
@Composable fun CalendarDayCell(date:LocalDate?,selected:String,summary:DayAggregate?,onSelect:(String)->Unit,modifier:Modifier=Modifier){ val iso=date?.format(DateUtils.iso); TextButton(onClick={ if(iso!=null) onSelect(iso) },enabled=date!=null,modifier=modifier.height(58.dp)){ Column(horizontalAlignment=Alignment.CenterHorizontally){ Text(date?.dayOfMonth?.toString() ?: "", color=if(iso==selected) GritAccent else MaterialTheme.colorScheme.onSurface); Row(horizontalArrangement=Arrangement.spacedBy(2.dp)){ dotColors(summary).take(5).forEach{ Box(Modifier.size(5.dp).background(it,CircleShape)) } } } } }
fun dotColors(day:DayAggregate?):List<Color>{ if(day==null) return emptyList(); val dots= mutableListOf<Color>(); if(day.tasks.isNotEmpty()) dots+=GritAccent; day.logs.mapTo(dots){ when(it.label){"Positive"->Positive;"Negative"->Negative;else->Neutral} }; if(day.routines.isNotEmpty()) dots+=Routine; if(day.journal!=null) dots+=Journal; return dots.distinct() }
@Composable fun TodaySection(selected:String,onToday:()->Unit){ Card{ Row(Modifier.fillMaxWidth().padding(16.dp),horizontalArrangement=Arrangement.SpaceBetween,verticalAlignment=Alignment.CenterVertically){ Column{ Text("Today section",style=MaterialTheme.typography.titleMedium); Text("Selected: $selected",color=MaterialTheme.colorScheme.onSurfaceVariant) }; Button(onClick=onToday){Text("Today")} } } }
@Composable fun DayDetailPanel(date:String,day:DayAggregate?,onSaveJournal:(String)->Unit){ Card{ Column(Modifier.padding(16.dp),verticalArrangement=Arrangement.spacedBy(12.dp)){ Text(DateUtils.display(date),style=MaterialTheme.typography.titleLarge); JournalCard(day?.journal?.note,onSaveJournal); Text("Tasks",fontWeight=FontWeight.Bold); if(day?.tasks.isNullOrEmpty()) Text("No tasks recorded.") else day!!.tasks.forEach{Text("• ${it.title} — ${it.status}")}; Text("Habits / Actions",fontWeight=FontWeight.Bold); if(day?.logs.isNullOrEmpty()) Text("No action logs.") else day!!.logs.forEach{Text("• ${TimeUtils.displayTime(it.loggedAt)} — Action #${it.trackedActionId} — ${it.label}${it.note?.let{n->" — $n"}?:""}")}; Text("Routines",fontWeight=FontWeight.Bold); if(day?.routines.isNullOrEmpty()) Text("No routine records.") else day!!.routines.forEach{Text("• Routine #${it.routineId} — ${it.status}")} } } }
@Composable fun JournalCard(note:String?,onSave:(String)->Unit){ var draft by remember(note){ mutableStateOf(note ?: "") }; Column(verticalArrangement=Arrangement.spacedBy(8.dp)){ Text("Journal",fontWeight=FontWeight.Bold); OutlinedTextField(draft,{draft=it},label={Text("Add a note or photo for today.")},modifier=Modifier.fillMaxWidth(),minLines=2); Button(onClick={onSave(draft)},enabled=draft.isNotBlank()){Text("Save journal note")}; if(note!=null) Text("Saved note: $note",color=MaterialTheme.colorScheme.onSurfaceVariant) } }
